import React, { useState } from 'react';
import { faTachometerAlt, fa, faBowlFood, faBook, faScroll, faCreditCard } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { useNavigate } from 'react-router-dom';

function SidebarComponent({ now }) {
    const admin = localStorage.getItem("admin")

    // navigate
    const navigate = useNavigate()

    // states
    const [current, setCurrent] = useState(now)

    // return
    return (
        <div className="hidden md:block md:w-60 lg:w-full max-w-80 min-h-screen fixed border border-gray-500 border-right mt-16 bg-gray-400">
            <div className="w-full min-h-screen">
                <div onClick={() => {setCurrent('dashboard'); navigate('/hostel/dashboard')}} className={current === "dashboard" ? "flex flex-row w-full bg-blue-800 px-8 py-3" : "flex flex-row w-full hover:bg-gray-500 px-8 py-3"}>
                    <FontAwesomeIcon className="mt-1" icon={faTachometerAlt} color={current === "dashboard" ? "white" : "black"} size="md" />
                    <h1 className={current === "dashboard" ? "text-md font-semibold text-white ml-2" : "text-md font-semibold text-black ml-2"}>Dashboard</h1>
                </div>
                <div onClick={() => {setCurrent('students'); navigate('/hostel/students')}} className={current === "students" ? "flex flex-row w-full bg-blue-800 px-8 py-3" : "flex flex-row w-full hover:bg-gray-500 px-8 py-3"}>
                    <FontAwesomeIcon className="mt-1" icon={faUsers} color={current === "students" ? "white" : "black"} size="md" />
                    <h1 className={current === "students" ? "text-md font-semibold text-white ml-2" : "text-md font-semibold text-black ml-2"}>Students</h1>
                </div>
                <div onClick={() => {setCurrent('rooms'); navigate('/hostel/rooms')}} className={current === "rooms" ? "flex flex-row w-full bg-blue-800 px-8 py-3" : "flex flex-row w-full hover:bg-gray-500 px-8 py-3"}>
                    <FontAwesomeIcon className="mt-1" icon={faBowlFood} color={current === "rooms" ? "white" : "black"} size="md" />
                    <h1 className={current === "rooms" ? "text-md font-semibold text-white ml-2" : "text-md font-semibold text-black ml-2"}>Rooms</h1>
                </div>
                <div onClick={() => {setCurrent('orders'); navigate('/hostel/orders')}} className={current === "orders" ? "flex flex-row w-full bg-blue-800 px-8 py-3" : "flex flex-row w-full hover:bg-gray-500 px-8 py-3"}>
                    <FontAwesomeIcon className="mt-1" icon={faScroll} color={current === "orders" ? "white" : "black"} size="md" />
                    <h1 className={current === "orders" ? "text-md font-semibold text-white ml-2" : "text-md font-semibold text-black ml-2"}>Orders</h1>
                </div>
                <div onClick={() => {setCurrent('payment_dues'); navigate('/hostel/payment_dues')}} className={current === "payment_dues" ? "flex flex-row w-full bg-blue-800 px-8 py-3" : "flex flex-row w-full hover:bg-gray-500 px-8 py-3"}>
                    <FontAwesomeIcon className="mt-1" icon={faCreditCard} color={current === "payment_dues" ? "white" : "black"} size="md" />
                    <h1 className={current === "payment_dues" ? "text-md font-semibold text-white ml-2" : "text-md font-semibold text-black ml-2"}>Payment Dues</h1>
                </div>
            </div>
        </div>
    );
}

export default SidebarComponent;
